  1→//! Value shrinking for minimal witness discovery and boundary refinement.
  2→//!
  3→//! Given a value and its `TypeInfo`, produces progressively simpler variants.
  4→//! Conceptual inverse of `mutate_value` in `input_gen.rs`: mutation goes toward
  5→//! novelty, shrinking goes toward simplicity.
  6→
  7→use serde_json::{json, Value};
  8→
  9→use crate::types::TypeInfo;
 10→
 11→// Boundary values used as shrink targets for numeric types.
 12→const SHRINK_INT_ZERO: i64 = 0;
 13→const SHRINK_INT_ONE: i64 = 1;
 14→const SHRINK_INT_NEG_ONE: i64 = -1;
 15→
 16→const SHRINK_FLOAT_ZERO: f64 = 0.0;
 17→const SHRINK_FLOAT_ONE: f64 = 1.0;
 18→const SHRINK_FLOAT_NEG_ONE: f64 = -1.0;
 19→
 20→/// Produce simpler variants of `value` that still conform to `type_info`.
 21→///
 22→/// Never includes the original value. Returns an empty vec for types that
 23→/// cannot be meaningfully shrunk (Complex, Opaque, Unknown) or values that
 24→/// are already minimal.
 25→pub fn shrink_candidates(value: &Value, type_info: &TypeInfo) -> Vec<Value> {
 26→    let mut candidates = match type_info {
 27→        TypeInfo::Int => shrink_int(value),
 28→        TypeInfo::Float => shrink_float(value),
 29→        TypeInfo::Str => shrink_string(value),
 30→        TypeInfo::Bool => shrink_bool(value),
 31→        TypeInfo::Array { element } => shrink_array(value, element),
 32→        TypeInfo::Object { fields } => shrink_object(value, fields),
 33→        TypeInfo::Nullable { inner } => shrink_nullable(value, inner),
 34→        TypeInfo::Union { variants } => shrink_union(value, variants),
 35→        TypeInfo::Complex { .. } | TypeInfo::Opaque { .. } | TypeInfo::Unknown => Vec::new(),
 36→    };
 37→
 38→    // Remove duplicates and the original value.
 39→    candidates.retain(|c| c != value);
 40→    dedup_values(&mut candidates);
 41→    candidates
 42→}
 43→
 44→/// Deduplicate a vec of Values, preserving order (keeps first occurrence).
 45→fn dedup_values(values: &mut Vec<Value>) {
 46→    let mut seen = Vec::with_capacity(values.len());
 47→    values.retain(|v| {
 48→        if seen.contains(v) {
 49→            false
 50→        } else {
 51→            seen.push(v.clone());
 52→            true
 53→        }
 54→    });
 55→}
 56→
 57→fn shrink_int(value: &Value) -> Vec<Value> {
 58→    let n = match value.as_i64() {
 59→        Some(n) => n,
 60→        None => return vec![json!(SHRINK_INT_ZERO)],
 61→    };
 62→
 63→    let mut out = Vec::with_capacity(4);
 64→
 65→    // Halve toward zero.
 66→    if n != 0 {
 67→        out.push(json!(n / 2));
 68→    }
 69→
 70→    out.push(json!(SHRINK_INT_ZERO));
 71→    out.push(json!(SHRINK_INT_ONE));
 72→    out.push(json!(SHRINK_INT_NEG_ONE));
 73→
 74→    out
 75→}
 76→
 77→fn shrink_float(value: &Value) -> Vec<Value> {
 78→    let n = match value.as_f64() {
 79→        Some(n) => n,
 80→        None => return vec![json!(SHRINK_FLOAT_ZERO)],
 81→    };
 82→
 83→    let mut out = Vec::with_capacity(4);
 84→
 85→    // Halve toward zero.
 86→    if n != 0.0 {
 87→        out.push(json!(n / 2.0));
 88→    }
 89→
 90→    out.push(json!(SHRINK_FLOAT_ZERO));
 91→    out.push(json!(SHRINK_FLOAT_ONE));
 92→    out.push(json!(SHRINK_FLOAT_NEG_ONE));
 93→
 94→    out
 95→}
 96→
 97→fn shrink_string(value: &Value) -> Vec<Value> {
 98→    let s = match value.as_str() {
 99→        Some(s) => s,
100→        None => return vec![json!("")],
101→    };
102→
103→    let mut out = Vec::with_capacity(4);
104→
105→    // Remove last character.
106→    if !s.is_empty() {
107→        let without_last: String = s.chars().take(s.chars().count() - 1).collect();
108→        out.push(json!(without_last));
109→    }
110→
111→    // Remove first character.
112→    if s.chars().count() > 1 {
113→        let without_first: String = s.chars().skip(1).collect();
114→        out.push(json!(without_first));
115→    }
116→
117→    // Empty string.
118→    out.push(json!(""));
119→
120→    // Single first character.
121→    if let Some(ch) = s.chars().next()
122→        && s.chars().count() > 1
123→    {
124→        out.push(json!(ch.to_string()));
125→    }
126→
127→    out
128→}
129→
130→fn shrink_bool(value: &Value) -> Vec<Value> {
131→    match value.as_bool() {
132→        Some(true) => vec![json!(false)],
133→        _ => Vec::new(),
134→    }
135→}
136→
137→fn shrink_array(value: &Value, element: &TypeInfo) -> Vec<Value> {
138→    let arr = match value.as_array() {
139→        Some(a) => a,
140→        None => return vec![json!([])],
141→    };
142→
143→    if arr.is_empty() {
144→        return Vec::new();
145→    }
146→
147→    let mut out = Vec::with_capacity(3 + arr.len());
148→
149→    // Remove last element.
150→    if arr.len() > 1 {
151→        out.push(Value::Array(arr[..arr.len() - 1].to_vec()));
152→    }
153→
154→    // Remove first element.
155→    if arr.len() > 1 {
156→        out.push(Value::Array(arr[1..].to_vec()));
157→    }
158→
159→    // Empty array.
160→    out.push(json!([]));
161→
162→    // Shrink individual elements in place.
163→    for (i, elem) in arr.iter().enumerate() {
164→        for shrunk in shrink_candidates(elem, element) {
165→            let mut new_arr = arr.clone();
166→            new_arr[i] = shrunk;
167→            out.push(Value::Array(new_arr));
168→        }
169→    }
170→
171→    out
172→}
173→
174→fn shrink_object(value: &Value, fields: &[(String, TypeInfo)]) -> Vec<Value> {
175→    let obj = match value.as_object() {
176→        Some(o) => o,
177→        None => return Vec::new(),
178→    };
179→
180→    let mut out = Vec::with_capacity(fields.len());
181→
182→    // Remove each field one at a time.
183→    for (field_name, _) in fields {
184→        if obj.contains_key(field_name) {
185→            let mut shrunk = obj.clone();
186→            shrunk.remove(field_name);
187→            out.push(Value::Object(shrunk));
188→        }
189→    }
190→
191→    // Shrink individual field values in place.
192→    for (field_name, field_type) in fields {
193→        if let Some(field_val) = obj.get(field_name) {
194→            for shrunk_val in shrink_candidates(field_val, field_type) {
195→                let mut new_obj = obj.clone();
196→                new_obj.insert(field_name.clone(), shrunk_val);
197→                out.push(Value::Object(new_obj));
198→            }
199→        }
200→    }
201→
202→    out
203→}
204→
205→fn shrink_nullable(value: &Value, inner: &TypeInfo) -> Vec<Value> {
206→    let mut out = Vec::with_capacity(4);
207→
208→    // Always try null.
209→    out.push(Value::Null);
210→
211→    // If not already null, also shrink the inner value.
212→    if !value.is_null() {
213→        out.extend(shrink_candidates(value, inner));
214→    }
215→
216→    out
217→}
218→
219→fn shrink_union(value: &Value, variants: &[TypeInfo]) -> Vec<Value> {
220→    let mut out = Vec::new();
221→
222→    // Try shrinking against each variant — collect all candidates.
223→    for variant in variants {
224→        out.extend(shrink_candidates(value, variant));
225→    }
226→
227→    out
228→}
