230→#[cfg(test)]
231→mod tests {
232→    use super::*;
233→    use serde_json::json;
234→
235→    // -----------------------------------------------------------------------
236→    // Int
237→    // -----------------------------------------------------------------------
238→
239→    #[test]
240→    fn shrink_int_positive() {
241→        let candidates = shrink_candidates(&json!(10), &TypeInfo::Int);
242→        assert!(candidates.contains(&json!(5))); // halve
243→        assert!(candidates.contains(&json!(0)));
244→        assert!(candidates.contains(&json!(1)));
245→        assert!(candidates.contains(&json!(-1)));
246→        assert!(!candidates.contains(&json!(10))); // never original
247→    }
248→
249→    #[test]
250→    fn shrink_int_negative() {
251→        let candidates = shrink_candidates(&json!(-8), &TypeInfo::Int);
252→        assert!(candidates.contains(&json!(-4))); // halve toward zero
253→        assert!(candidates.contains(&json!(0)));
254→    }
255→
256→    #[test]
257→    fn shrink_int_zero_already_minimal() {
258→        let candidates = shrink_candidates(&json!(0), &TypeInfo::Int);
259→        assert!(!candidates.contains(&json!(0)));
260→        // Still offers 1 and -1 as alternatives.
261→        assert!(candidates.contains(&json!(1)));
262→        assert!(candidates.contains(&json!(-1)));
263→    }
264→
265→    #[test]
266→    fn shrink_int_one_no_duplicate() {
267→        let candidates = shrink_candidates(&json!(1), &TypeInfo::Int);
268→        assert!(!candidates.contains(&json!(1)));
269→        let count = candidates.iter().filter(|c| **c == json!(0)).count();
270→        assert_eq!(count, 1, "no duplicate zeros");
271→    }
