280→        assert!(candidates.contains(&json!(2.0)));
281→        assert!(candidates.contains(&json!(0.0)));
282→        assert!(!candidates.contains(&json!(4.0)));
283→    }
284→
285→    #[test]
286→    fn shrink_float_zero_already_minimal() {
287→        let candidates = shrink_candidates(&json!(0.0), &TypeInfo::Float);
288→        assert!(!candidates.contains(&json!(0.0)));
289→    }
