295→    #[test]
296→    fn shrink_string_multi_char() {
297→        let candidates = shrink_candidates(&json!("hello"), &TypeInfo::Str);
298→        assert!(candidates.contains(&json!("hell"))); // drop last
299→        assert!(candidates.contains(&json!("ello"))); // drop first
300→        assert!(candidates.contains(&json!(""))); // empty
301→        assert!(candidates.contains(&json!("h"))); // first char
302→        assert!(!candidates.contains(&json!("hello")));
303→    }
304→
305→    #[test]
306→    fn shrink_string_single_char() {
307→        let candidates = shrink_candidates(&json!("x"), &TypeInfo::Str);
308→        assert!(candidates.contains(&json!("")));
309→        // Removing last char of "x" gives "" which is already in the list.
310→        assert!(!candidates.contains(&json!("x")));
311→    }
312→
313→    #[test]
314→    fn shrink_string_empty_already_minimal() {
315→        let candidates = shrink_candidates(&json!(""), &TypeInfo::Str);
316→        assert!(candidates.is_empty());
317→    }
