339→    #[test]
340→    fn shrink_array_multiple_elements() {
341→        let typ = TypeInfo::Array {
342→            element: Box::new(TypeInfo::Int),
343→        };
344→        let candidates = shrink_candidates(&json!([1, 2, 3]), &typ);
345→        assert!(candidates.contains(&json!([1, 2]))); // drop last
346→        assert!(candidates.contains(&json!([2, 3]))); // drop first
347→        assert!(candidates.contains(&json!([]))); // empty
