371→    // -----------------------------------------------------------------------
372→    // Object
373→    // -----------------------------------------------------------------------
374→
375→    #[test]
376→    fn shrink_object_removes_fields() {
377→        let typ = TypeInfo::Object {
378→            fields: vec![
379→                ("a".into(), TypeInfo::Int),
380→                ("b".into(), TypeInfo::Str),
381→            ],
382→        };
383→        let val = json!({"a": 10, "b": "hi"});
384→        let candidates = shrink_candidates(&val, &typ);
385→
386→        // Should have field-removal candidates.
387→        assert!(candidates.contains(&json!({"b": "hi"}))); // removed "a"
388→        assert!(candidates.contains(&json!({"a": 10}))); // removed "b"
389→
390→        // Should also have field-value-shrunk candidates.
391→        assert!(candidates.contains(&json!({"a": 5, "b": "hi"}))); // shrunk "a"
392→        assert!(candidates.contains(&json!({"a": 10, "b": "h"}))); // shrunk "b"
393→
394→        assert!(!candidates.contains(&val));
395→    }
