476→    // Invariants
477→    // -----------------------------------------------------------------------
478→
479→    #[test]
480→    fn candidates_never_contain_original() {
481→        let cases: Vec<(Value, TypeInfo)> = vec![
482→            (json!(0), TypeInfo::Int),
483→            (json!(1), TypeInfo::Int),
484→            (json!(-1), TypeInfo::Int),
485→            (json!(42), TypeInfo::Int),
486→            (json!(0.0), TypeInfo::Float),
487→            (json!(3.14), TypeInfo::Float),
488→            (json!(""), TypeInfo::Str),
489→            (json!("a"), TypeInfo::Str),
490→            (json!("hello"), TypeInfo::Str),
491→            (json!(true), TypeInfo::Bool),
492→            (json!(false), TypeInfo::Bool),
493→            (json!(null), TypeInfo::Nullable { inner: Box::new(TypeInfo::Int) }),
494→            (json!([]), TypeInfo::Array { element: Box::new(TypeInfo::Int) }),
495→            (json!([1, 2]), TypeInfo::Array { element: Box::new(TypeInfo::Int) }),
496→        ];
497→
498→        for (val, typ) in &cases {
499→            let candidates = shrink_candidates(val, typ);
500→            assert!(
501→                !candidates.contains(val),
502→                "candidates for {:?} should not contain original",
503→                val
504→            );
505→        }
506→    }
507→
508→    #[test]
509→    fn no_duplicate_candidates() {
510→        let cases: Vec<(Value, TypeInfo)> = vec![
511→            (json!(10), TypeInfo::Int),
512→            (json!("hello"), TypeInfo::Str),
513→            (json!([1, 2, 3]), TypeInfo::Array { element: Box::new(TypeInfo::Int) }),
514→        ];
515→
516→        for (val, typ) in &cases {
517→            let candidates = shrink_candidates(val, typ);
518→            for (i, a) in candidates.iter().enumerate() {
519→                for (j, b) in candidates.iter().enumerate() {
520→                    if i != j {
521→                        assert_ne!(a, b, "duplicate candidate in shrink of {:?}", val);
522→                    }
523→                }
524→            }
525→        }
526→    }
