1630→fn shrink_int(value: &Value) -> Vec<Value> {
1631→    let n = match value.as_i64() {
1632→        Some(n) => n,
1633→        None => return Vec::new(),
1634→    };
1635→    let mut out = Vec::with_capacity(4);
1636→    let half = n / 2;
1637→    if half != n {
1638→        out.push(json!(half));
1639→    }
1640→    if n != 0 {
1641→        out.push(json!(0));
1642→    }
1643→    if n != 1 {
1644→        out.push(json!(1));
1645→    }
1646→    if n != -1 {
1647→        out.push(json!(-1));
1648→    }
1649→    out
1650→}
1651→
1652→fn shrink_float(value: &Value) -> Vec<Value> {
1653→    let n = match value.as_f64() {
1654→        Some(n) if n.is_finite() => n,
1655→        // NaN / Infinity / non-float → shrink to 0.0
1656→        Some(_) => return vec![json!(0.0)],
1657→        None => return Vec::new(),
1658→    };
1659→    let mut out = Vec::with_capacity(4);
1660→    let half = n / 2.0;
1661→    if (half - n).abs() > f64::EPSILON {
1662→        out.push(json!(half));
1663→    }
1664→    if n.abs() > f64::EPSILON {
1665→        out.push(json!(0.0));
1666→    }
1667→    if (n - 1.0).abs() > f64::EPSILON {
1668→        out.push(json!(1.0));
1669→    }
1670→    if (n + 1.0).abs() > f64::EPSILON {
1671→        out.push(json!(-1.0));
1672→    }
1673→    out
1674→}
1675→
1676→fn shrink_str(value: &Value) -> Vec<Value> {
1677→    let s = match value.as_str() {
1678→        Some(s) => s,
1679→        None => return Vec::new(),
1680→    };
1681→    if s.is_empty() {
1682→        return Vec::new();
1683→    }
1684→    let chars: Vec<char> = s.chars().collect();
1685→    let mut out = Vec::with_capacity(4);
1686→    // Remove last char
1687→    if chars.len() > 1 {
1688→        let without_last: String = chars[..chars.len() - 1].iter().collect();
1689→        out.push(json!(without_last));
1690→    }
1691→    // Remove first char
1692→    if chars.len() > 1 {
1693→        let without_first: String = chars[1..].iter().collect();
1694→        out.push(json!(without_first));
1695→    }
1696→    // Empty string
1697→    out.push(json!(""));
1698→    // Single first char
1699→    if chars.len() > 1 {
1700→        out.push(json!(chars[0].to_string()));
1701→    }
1702→    out
1703→}
1704→
1705→fn shrink_bool(value: &Value) -> Vec<Value> {
1706→    match value.as_bool() {
1707→        Some(true) => vec![json!(false)],
1708→        _ => Vec::new(),
1709→    }
1710→}
1711→
1712→fn shrink_array(value: &Value, element: &TypeInfo) -> Vec<Value> {
1713→    let arr = match value.as_array() {
1714→        Some(a) => a,
1715→        None => return Vec::new(),
1716→    };
1717→    if arr.is_empty() {
1718→        return Vec::new();
1719→    }
1720→    let mut out = Vec::with_capacity(3 + arr.len());
1721→    // Remove last element
1722→    if arr.len() > 1 {
1723→        out.push(json!(arr[..arr.len() - 1]));
1724→    }
1725→    // Remove first element
1726→    if arr.len() > 1 {
1727→        out.push(json!(arr[1..]));
1728→    }
1729→    // Empty array
1730→    out.push(json!([]));
1731→    // Shrink each element individually
1732→    for (i, elem) in arr.iter().enumerate() {
1733→        for shrunk in shrink_candidates(elem, element) {
1734→            let mut new_arr = arr.clone();
1735→            new_arr[i] = shrunk;
1736→            out.push(Value::Array(new_arr));
1737→        }
1738→    }
1739→    out
1740→}
1741→
1742→fn shrink_object(value: &Value, fields: &[(String, TypeInfo)]) -> Vec<Value> {
1743→    let obj = match value.as_object() {
1744→        Some(o) => o,
1745→        None => return Vec::new(),
1746→    };
1747→    if fields.is_empty() {
1748→        return Vec::new();
1749→    }
1750→    let mut out = Vec::with_capacity(fields.len() * 2);
1751→    // Remove each field one at a time
1752→    for (name, _) in fields {
1753→        if obj.contains_key(name) {
1754→            let mut reduced = obj.clone();
1755→            reduced.remove(name);
1756→            out.push(Value::Object(reduced));
1757→        }
1758→    }
1759→    // Shrink each field value individually
1760→    for (name, typ) in fields {
1761→        if let Some(val) = obj.get(name) {
1762→            for shrunk in shrink_candidates(val, typ) {
1763→                let mut new_obj = obj.clone();
1764→                new_obj.insert(name.clone(), shrunk);
1765→                out.push(Value::Object(new_obj));
1766→            }
1767→        }
1768→    }
1769→    out
1770→}
1771→
1772→fn shrink_nullable(value: &Value, inner: &TypeInfo) -> Vec<Value> {
1773→    let mut out = Vec::with_capacity(4);
1774→    if !value.is_null() {
1775→        out.push(Value::Null);
1776→        out.extend(shrink_candidates(value, inner));
1777→    }
1778→    out
1779→}
1780→
1781→fn shrink_union(value: &Value, variants: &[TypeInfo]) -> Vec<Value> {
1782→    let mut out = Vec::new();
1783→    for variant in variants {
1784→        out.extend(shrink_candidates(value, variant));
1785→    }
1786→    out
1787→}
